parameters.jsCode:
const raw = $input.first().json;
const content = raw.message.content;
let parsed;

try {
  // Try to extract JSON from the response
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : { hook: '', body: content, cta: '' };
} catch (e) {
  parsed = { hook: raw.hook_text || '', body: content, cta: '', word_count: content.split(' ').length };
}

return {
  hook_text: parsed.hook || $json.hook_text,
  body_text: parsed.body || content,
  cta_text: parsed.cta || '',
  word_count: parsed.word_count || content.split(' ').length,
  ai_prompt: $json.ai_prompt || '',
  ai_model: 'gpt-4-turbo',
  tokens_used: raw.usage?.total_tokens || 0,
  category: $json.hook_category || $json.category || '',
  estimated_performance: $json.estimated_performance || null,
  hook_id: $json.hook_id
};
